namespace sv_57517dee5799433989f7a353802a661a.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Italian pizza with fresh mozzarella, tomatoes, and basil.", 30),
            new(2, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan.", 45),
            new(3, "Tiramisu", "Layered coffee-flavored dessert with mascarpone cream.", 40),
        },
        [2] = new List<Recipe>
        {
            new(4, "Pad Thai", "Stir-fried rice noodles with shrimp, peanuts, and tamarind sauce.", 25),
            new(5, "Green Curry", "Spicy coconut milk curry with vegetables and Thai basil.", 35),
            new(6, "Tom Yum Soup", "Hot and sour soup with lemongrass, galangal, and prawns.", 20),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple and cilantro.", 50),
            new(8, "Guacamole", "Fresh avocado dip with lime, onion, and jalapeño.", 10),
            new(9, "Churros", "Fried dough pastries coated in cinnamon sugar.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_57517dee5799433989f7a353802a661a.Services
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p class="text-muted"><small>Refreshing…</small></p>
    }

    <ul>
        @foreach (var recipe in DisplayedRecipes)
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <span class="text-muted">(@recipe.PrepTimeMinutes min)</span>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _errorMessage;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes =>
        Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes!.OrderByDescending(r => r.Id),
            "popular" => _recipes!.OrderBy(r => r.PrepTimeMinutes),
            _ => _recipes!
        };

    protected override Task OnParametersSetAsync()
    {
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }
        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _errorMessage = null;
        _isRefreshing = _recipes is not null;
        var targetCuisineId = CuisineId;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(targetCuisineId, token);
            _recipes = results;
            _loadedCuisineId = targetCuisineId;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Navigation changed cuisine; do nothing — the new load handles it.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", targetCuisineId);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", targetCuisineId);
            _errorMessage = "Something went wrong loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

